const { sql } = require('slonik');

async function solve({ skillTags, difficulty, limit }) {
  // Normalize skillTags input to lowercase array
  let normalizedTags = [];
  if (skillTags) {
    if (Array.isArray(skillTags)) {
      normalizedTags = skillTags
        .flatMap(t => t.split(','))
        .map(t => t.trim().toLowerCase())
        .filter(t => t.length > 0);
    } else if (typeof skillTags === 'string') {
      normalizedTags = skillTags
        .split(',')
        .map(t => t.trim().toLowerCase())
        .filter(t => t.length > 0);
    }
  }

  // Compose WHERE clauses
  const whereClauses = [];
  const params = [];

  if (difficulty) {
    whereClauses.push(sql`difficulty = ${difficulty}`);
  }

  if (normalizedTags.length > 0) {
    // Filter problems that have any of the normalized tags (case-insensitive)
    whereClauses.push(sql`EXISTS (
      SELECT 1 FROM problem_tags pt
      WHERE pt.problem_id = p.id AND LOWER(pt.tag) = ANY(${normalizedTags})
    )`);
  }

  // Compose final query
  const query = sql`
    SELECT p.*, 
      ARRAY(
        SELECT DISTINCT LOWER(pt.tag) FROM problem_tags pt WHERE pt.problem_id = p.id
      ) AS appliedTags
    FROM problems p
    ${whereClauses.length > 0 ? sql`WHERE ${sql.join(whereClauses, sql` AND `)}` : sql``}
    ORDER BY p.roundId ASC
    ${limit ? sql`LIMIT ${limit}` : sql``}
  `;

  // Run query and return results with metadata
  const problems = await this.db.any(query);

  return {
    problems,
    metadata: {
      appliedTags: normalizedTags,
    },
  };
}

module.exports = { solve };
